export function getCombination(comboSlug: string, locationSlug: string): Combination | undefined {
  return combinations.find(c => c.comboSlug === comboSlug && c.locationSlug === locationSlug);
}

export function getCombinationsByService(serviceSlug: string): Combination[] {
  return combinations.filter(c => c.serviceSlug === serviceSlug);
}

export function getCombinationsByLocation(locationSlug: string): Combination[] {
  return combinations.filter(c => c.locationSlug === locationSlug);
}
